import React from "react";

const MACHINES = [
  { src: "/air_to_water_heat_pump.svg", left: "2%", top: "8%", size: 120, duration: 14, delay: 0 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "18%", top: "18%", size: 90, duration: 12, delay: 2 },
  { src: "/water_to_water_heat_pump.svg", left: "35%", top: "5%", size: 110, duration: 16, delay: 4 },
  { src: "/ground_source_heat_pump.svg", left: "52%", top: "14%", size: 100, duration: 13, delay: 1 },
  { src: "/air_to_water_heat_pump.svg", left: "68%", top: "6%", size: 115, duration: 15, delay: 3 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "84%", top: "16%", size: 85, duration: 11, delay: 5 },
  { src: "/water_to_water_heat_pump.svg", left: "6%", top: "38%", size: 105, duration: 14, delay: 6 },
  { src: "/ground_source_heat_pump.svg", left: "22%", top: "48%", size: 95, duration: 12, delay: 0 },
  { src: "/air_to_water_heat_pump.svg", left: "40%", top: "35%", size: 75, duration: 10, delay: 7 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "58%", top: "42%", size: 88, duration: 13, delay: 2 },
  { src: "/water_to_water_heat_pump.svg", left: "74%", top: "32%", size: 125, duration: 15, delay: 8 },
  { src: "/ground_source_heat_pump.svg", left: "90%", top: "45%", size: 92, duration: 11, delay: 4 },
  { src: "/air_to_water_heat_pump.svg", left: "4%", top: "68%", size: 100, duration: 12, delay: 9 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "20%", top: "78%", size: 80, duration: 14, delay: 3 },
  { src: "/water_to_water_heat_pump.svg", left: "38%", top: "62%", size: 110, duration: 10, delay: 1 },
  { src: "/ground_source_heat_pump.svg", left: "55%", top: "72%", size: 98, duration: 13, delay: 6 },
  { src: "/air_to_water_heat_pump.svg", left: "72%", top: "65%", size: 85, duration: 11, delay: 10 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "88%", top: "75%", size: 105, duration: 15, delay: 5 },
  { src: "/water_to_water_heat_pump.svg", left: "48%", top: "88%", size: 70, duration: 12, delay: 7 },
  { src: "/ground_source_heat_pump.svg", left: "30%", top: "28%", size: 65, duration: 10, delay: 8 },
];

export default function BackgroundMachines() {
  return (
    <div className="bg-machines" aria-hidden="true">
      {MACHINES.map((m, i) => (
        <img
          key={i}
          className="bg-machine"
          src={m.src}
          alt=""
          style={{
            left: m.left,
            top: m.top,
            width: m.size,
            height: m.size,
            animationDuration: `${m.duration}s`,
            animationDelay: `${m.delay}s`,
          }}
        />
      ))}
    </div>
  );
}
